export type LogLevel = 'debug' | 'error' | 'fatal' | 'info' | 'trace' | 'warn';
/**
 * Resolves the initial log level for a logger instance.
 * LOG_DEBUG match → trace. Otherwise: LOG_LEVEL > optionLevel > 'info'.
 */
export declare function getInitialLevel(loggerName: string, optionLevel?: LogLevel): LogLevel;
